	var x = 5;
	var wheelWidth = 10;
	var a = obj.area;

	var totalTravel = 51;
	var bottomPad = 2;
	var v = (obj.value * totalTravel) + bottomPad;

	var numLines = 60;
	var lineSpacing = 2;

