	var wheelColour = 0xFF0F7691;
	var shadeColour = 0xFF0B0925;
	var lightColour = 0x38FFFFFF;

	g.setColour(bgColour);
	g.fillRect(obj.area);

	g.setColour(Colours.black);
	g.fillRect([x, 0, wheelWidth, a[3]]);

	g.setColour(0xFB24252B);
	g.drawVerticalLine(3, 0, 60);
	g.drawVerticalLine(16, 0, 60);

	g.setColour(wheelColour);

	for (var i = 0; i < numLines; i++)
	{
		var y = (2 * i) - v;
		g.drawHorizontalLine(y, x, wheelWidth + x);
	}

	g.setColour(wheelColour);
	g.drawHorizontalLine(53 - v, x, wheelWidth + x);
	g.drawHorizontalLine(55 - v, x, wheelWidth + x);
	g.drawHorizontalLine(57 - v, x, wheelWidth + x);
	g.drawHorizontalLine(59 - v, x, wheelWidth + x);

	g.setGradientFill([0xFF181515, 6, 0, 0x00000000, 6, 15]);
	g.fillRect(obj.area);

	g.setGradientFill([0x00000000, 6, 30, shadeColour, 6, 60]);
	g.fillRect(obj.area);

	g.setGradientFill([0x00000000, 6, 0, lightColour, 6, 15]);
	g.fillRect([x, 0, wheelWidth, 15]);

	g.setGradientFill([lightColour, 6, 15, 0x00000000, 6, 40]);
	g.fillRect([x, 15, wheelWidth, 30]);

	g.setColour(Colours.white);
	g.drawHorizontalLine(56 - v, x - 1, wheelWidth + x + 1);

	g.setColour(Colours.black);
	g.drawRect(a, 1);
});

